  1→import { describe, it, expect, beforeEach } from 'vitest';
  2→import { Hono } from 'hono';
  3→import {
  4→  checkAuth,
  5→  requireAuthenticatedUser,
  6→  onlySystemAdmin,
  7→  ensureTaskAuth,
  8→} from './auth-middleware';
  9→import type { ContextVars } from '../context';
 10→import { UserSchema } from '@/lib';
 11→import { fake, TestRouter, mockOAuth2ClientVerifyIdToken } from '@/testing';
 12→import { auth } from '@/lib/auth';
 13→import { db } from '@/db';
 14→import onError from './error-middleware';
 15→import { resetConfig } from '@/lib/gcp/config';
 16→
 17→// Helper to create a test app with error handling
 18→// By default includes checkAuth middleware (matching the real app setup)
 19→function createTestApp(options?: { skipCheckAuth?: boolean }) {
 20→  const app = new Hono<ContextVars>().onError(onError);
 21→
 22→  // Apply checkAuth by default (matching real app setup in app.ts)
 23→  if (!options?.skipCheckAuth) app.use(checkAuth);
 24→
 25→  return app;
 26→}
 27→
 28→async function expectJsonError(res: Response, message: string) {
 29→  const body = (await res.json()) as { error?: string; message?: string };
 30→  expect(body).toMatchObject({ error: message, message });
 31→}
 32→
 33→describe('checkAuth', () => {
 34→  it('sets auth to null when no session exists', async () => {
 35→    const app = createTestApp().get('/test', (c) => {
 36→      expect(c.var.auth).toBeNull();
 37→      return c.json({ success: true });
 38→    });
 39→
 40→    const router = TestRouter.create(app, auth);
 41→    const res = await router.get('/test');
 42→    expect(res.status).toBe(200);
 43→  });
 44→
 45→  it('sets auth to session when session exists', async () => {
 46→    // Create a real user in the database
 47→    const user = await db.users.create(fake(UserSchema, { banned: false, role: 'user' }));
 48→
 49→    const app = createTestApp().get('/test', (c) => {
 50→      expect(c.var.auth).toBeDefined();
 51→      expect(c.var.auth?.user).toBeDefined();
 52→      expect(c.var.auth?.user.id).toBe(user.id);
 53→      return c.json({ success: true });
 54→    });
 55→
 56→    const router = TestRouter.create(app, auth);
 57→    const res = await router.asUser(user).get('/test');
 58→    expect(res.status).toBe(200);
 59→  });
 60→});
 61→
 62→describe('requireAuthenticatedUser', () => {
 63→  it('throws 401 when auth is null', async () => {
 64→    const app = createTestApp()
 65→      .use(requireAuthenticatedUser)
 66→      .get('/test', (c) => c.json({ success: true }));
 67→
 68→    const router = TestRouter.create(app, auth);
 69→    const res = await router.get('/test');
 70→    expect(res.status).toBe(401);
 71→    await expectJsonError(res, 'Unauthorized');
 72→  });
 73→
 74→  it('sets currentUser when authenticated user exists', async () => {
 75→    // Create a real user in the database
 76→    const user = await db.users.create(fake(UserSchema, { banned: false, role: 'user' }));
 77→
 78→    const app = createTestApp()
 79→      .use(requireAuthenticatedUser)
 80→      .get('/test', (c) => {
 81→        expect(c.var.currentUser).toBeDefined();
 82→        expect(c.var.currentUser.id).toBe(user.id);
 83→        expect(c.var.currentUser.email).toBe(user.email);
 84→        return c.json({ success: true });
 85→      });
 86→
 87→    const router = TestRouter.create(app, auth);
 88→    const res = await router.asUser(user).get('/test');
 89→    expect(res.status).toBe(200);
 90→    const body = await res.json();
 91→    expect(body).toEqual({ success: true });
 92→  });
 93→
 94→  it('requires checkAuth to run first', async () => {
 95→    // This test verifies that requireAuthenticatedUser expects checkAuth to
 96→    // have run. If checkAuth hasn't run, auth won't be set in context
 97→    // Note: checkAuth is NOT used here (skipped via option)
 98→    const app = createTestApp({ skipCheckAuth: true })
 99→      .use(requireAuthenticatedUser)
100→      .get('/test', (c) => c.json({ success: true }));
101→
102→    const router = TestRouter.create(app, auth);
103→    // Since checkAuth didn't run, c.var.auth is undefined
104→    // requireAuthenticatedUser should throw 401
105→    const res = await router.get('/test');
106→    expect(res.status).toBe(401);
107→  });
108→});
109→
110→describe('onlySystemAdmin', () => {
111→  it('throws 403 when user is not admin', async () => {
112→    // Create a real user with 'user' role
113→    const user = await db.users.create(fake(UserSchema, { banned: false, role: 'user' }));
114→
115→    const app = createTestApp()
116→      .use(requireAuthenticatedUser)
117→      .use(onlySystemAdmin)
