123→    await expectJsonError(res, 'Forbidden');
124→  });
125→
126→  it('allows access when user is admin', async () => {
127→    // Create a real user with 'admin' role
128→    const user = await db.users.create(fake(UserSchema, { banned: false, role: 'admin' }));
129→
130→    const app = createTestApp()
131→      .use(requireAuthenticatedUser)
132→      .use(onlySystemAdmin)
