161→    const user = await db.users.create(fake(UserSchema, { banned: false, role: 'user' }));
162→
163→    const app = createTestApp()
164→      .use(requireAuthenticatedUser)
165→      .use(onlySystemAdmin)
166→      .get('/test', (c) => c.json({ success: true }));
167→
168→    const router = TestRouter.create(app, auth);
169→    const res = await router.asUser(user).get('/test');
170→    expect(res.status).toBe(403);
171→    await expectJsonError(res, 'Forbidden');
172→  });
173→});
