175→describe('middleware chain integration', () => {
176→  it('works correctly when all middleware are chained', async () => {
177→    // Create a real user with 'admin' role
178→    const user = await db.users.create(fake(UserSchema, { banned: false, role: 'admin' }));
179→
180→    const app = createTestApp()
181→      .use(requireAuthenticatedUser)
182→      .use(onlySystemAdmin)
