199→  it('properly handles unauthenticated requests in public route', async () => {
200→    const app = createTestApp()
201→      // Note: requireAuthenticatedUser is NOT used for public route
202→      .get('/public', (c) => {
203→        expect(c.var.auth).toBeNull();
