import { HTTPException } from 'hono/http-exception';
import { getReasonPhrase, StatusCodes } from 'http-status-codes';
import type { ContentfulStatusCode } from 'hono/utils/http-status';

/**
 * Base application error class that extends Hono's HTTPException.
 *
 * Provides a consistent error interface for the application with proper
 * HTTP status codes. All application-specific errors should extend this class.
 *
 * @example
 * ```typescript
 * throw new AppError(StatusCodes.NOT_FOUND, 'Resource not found');
 * ```
 */
export class AppError extends HTTPException {
  constructor(status: ContentfulStatusCode, options?: { message?: string; cause?: unknown }) {
    super(status, {
      message: options?.message ?? getReasonPhrase(status),
      cause: options?.cause,
    });
  }
}

/**
 * Bad Request Error (400)
 *
 * Used when the client's request is malformed or invalid.
 */
export class BadRequestError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.BAD_REQUEST, { message, ...options });
  }
}

/**
 * Unauthorized Error (401)
 *
 * Used when authentication is required but not provided or invalid.
 */
export class UnauthorizedError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.UNAUTHORIZED, { message, ...options });
  }
}

/**
 * Forbidden Error (403)
 *
 * Used when the user is authenticated but doesn't have permission
 * to perform the requested action.
 */
export class ForbiddenError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.FORBIDDEN, { message, ...options });
  }
}

/**
 * Not Found Error (404)
 *
 * Used when the requested resource doesn't exist.
 */
export class NotFoundError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.NOT_FOUND, { message, ...options });
  }
}

/**
 * Conflict Error (409)
 *
 * Used when the request conflicts with the current state of the resource,
 * such as when trying to create a duplicate resource.
 */
export class ConflictError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.CONFLICT, { message, ...options });
  }
}

/**
 * Unprocessable Entity Error (422)
 *
 * Used when the request is well-formed but contains semantic errors,
 * typically from validation failures.
 */
export class UnprocessableEntityError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.UNPROCESSABLE_ENTITY, { message, ...options });
  }
}

/**
 * Too Many Requests Error (429)
 *
 * Used when the client has exceeded rate limits.
 */
export class TooManyRequestsError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.TOO_MANY_REQUESTS, { message, ...options });
  }
}

/**
 * Insufficient Quota Error (429)
 *
 * Thrown when a request cannot proceed because the quota budget has been
 * exhausted. Surfaces as HTTP 429 to trigger Cloud Tasks retry semantics.
 */
export class InsufficientQuotaError extends TooManyRequestsError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(message ?? 'Insufficient quota available', options);
    this.name = 'InsufficientQuotaError';
  }
}

/**
 * Quota Deferred Error (202)
 *
 * Thrown when a task is deferred due to quota exhaustion. The task has been
 * successfully rescheduled for a future time, so this is treated as an
 * accepted request rather than a failure. Surfaces as HTTP 202 Accepted.
 */
export class QuotaDeferredError extends AppError {
  constructor(
    public readonly retryAt: Date,
    public readonly taskName: string,
    public readonly details?: Record<string, unknown>,
    options?: { cause?: unknown },
  ) {
    super(StatusCodes.ACCEPTED, {
      message: `Task deferred to ${retryAt.toISOString()} due to quota exhaustion`,
      ...options,
    });
    this.name = 'QuotaDeferredError';
  }

  /**
   * Override getResponse() to return a JSON response with deferral information
   * instead of the default error message.
   */
  override getResponse(): Response {
    return Response.json(
      {
        accepted: true,
        deferred: true,
        retryAt: this.retryAt.toISOString(),
        taskName: this.taskName,
        ...(this.details ?? {}),
      },
      { status: StatusCodes.ACCEPTED },
    );
  }
}

/**
 * Internal Server Error (500)
 *
 * Used for unexpected server errors. Should generally be caught and logged
 * rather than thrown directly by application code.
 */
export class InternalServerError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.INTERNAL_SERVER_ERROR, { message, ...options });
  }
}

/**
 * Service Unavailable Error (503)
 *
 * Used when the service is temporarily unavailable, such as during maintenance.
 */
export class ServiceUnavailableError extends AppError {
  constructor(message?: string, options?: { cause?: unknown }) {
    super(StatusCodes.SERVICE_UNAVAILABLE, { message, ...options });
  }
}

import type { FirebaseError } from 'firebase-admin';

/**
 * Type guard to check if an error is a FirebaseError
 *
 * Checks if the error has the structure of a FirebaseError by verifying it has
 * a 'code' property of type string. This works with both real Firebase errors
 * and our custom FirestoreError implementation.
 *
 * @example
 * ```typescript
 * if (isFirebaseError(error)) {
 *   console.log(error.code); // TypeScript knows error has 'code' property
 * }
 * ```
 */
export function isFirebaseError(err: unknown): err is FirebaseError & Error {
  return err instanceof Error && 'code' in err && typeof err.code === 'string';
}

/**
 * Firebase Firestore Error
 *
 * Represents errors from Firebase Firestore operations. Compatible with the
 * FirebaseError interface from firebase-admin, providing a consistent error
 * format with error codes for production error handling.
 *
 * This class extends Error and implements the FirebaseError interface structure
 * (with a `code` property), making it compatible with Firebase error handling
 * throughout the application.
 *
 * This class can be used in production code to convert errors from libraries
 * like zod-firebase-admin into Firebase-compatible error format.
 *
 * @example
 * ```typescript
 * throw new FirestoreError('Document not found', { code: 'not-found' });
 * ```
 */
export class FirestoreError extends Error implements FirebaseError {
  readonly code: string;

  constructor(message: string, options?: { code?: string; cause?: unknown }) {
    super(message, { cause: options?.cause });
    this.code = options?.code ?? 'internal';
    this.name = 'FirestoreError';
    // Set prototype explicitly for instanceof checks
    Object.setPrototypeOf(this, FirestoreError.prototype);
  }

  toJSON(): { code: string; message: string } {
    return {
      code: this.code,
      message: this.message,
    };
  }
}

