/**
 * @fileoverview Authentication middleware for Hono routes.
 *
 * Provides four middleware functions:
 * - `checkAuth`: Global, non-blocking session check (sets `c.var.auth`)
 * - `requireAuthenticatedUser`: Requires auth, throws 401 if missing (sets
 *   `c.var.currentUser`)
 * - `onlySystemAdmin`: Requires admin role, throws 403 if not admin
 * - `ensureTaskAuth`: Validates Cloud Tasks requests with OIDC token auth
 */
import { createMiddleware } from 'hono/factory';
import { OAuth2Client } from 'google-auth-library';
import { auth } from '../../lib/auth';
import type { ContextVars } from '../context';
import {
  ForbiddenError,
  UnauthorizedError,
  getLogger,
  getConfig,
  getBaseUrl,
  type User,
} from '@/lib';

const logger = getLogger('task-auth');

/**
 * Global authentication middleware that checks for a session but never blocks.
 *
 * This middleware should be applied globally to all routes. It attempts to
 * retrieve the session from the request headers and stores it in the context
 * for downstream middleware and route handlers to use.
 *
 * @example
 * ```typescript
 * // Apply globally
 * app.use(checkAuth);
 *
 * // Access in routes
 * app.get('/route', (c) => {
 *   const session = c.var.auth; // May be null if not authenticated
 * });
 * ```
 */
export const checkAuth = createMiddleware<ContextVars>(async (c, next) => {
  const session = await auth.api.getSession({ headers: c.req.raw.headers });
  c.set('auth', session ?? null);
  return next();
});

/**
 * Middleware that requires an authenticated user.
 *
 * This middleware checks if there is an authenticated user in the session. If
 * no user is found, it throws an HTTPException with status 401 (Unauthorized).
 * If a user exists, it sets the `currentUser` context variable for downstream
 * middleware and route handlers.
 *
 * **Prerequisites**: `checkAuth` middleware must run before this middleware.
 *
 * @throws {HTTPException} 401 if no authenticated user is found
 *
 * @example
 * ```typescript
 * app.get('/protected', requireAuthenticatedUser, (c) => {
 *   // Always present (guaranteed by middleware)
 *   const user = c.var.currentUser;
 * });
 * ```
 */
export const requireAuthenticatedUser = createMiddleware<ContextVars>(async (c, next) => {
  const session = c.var.auth;
  if (!session?.user) throw new UnauthorizedError();

  // "as unknown as User" is a bit dirty, but the better-auth user type is
  // identical to the shared User type, so it's safe to cast.
  const currentUser = session.user as unknown as User;
  c.set('currentUser', currentUser);
  return next();
});

/**
 * Middleware that restricts access to system administrators only.
 *
 * This middleware checks if the current user has the 'admin' role. If the
 * user is not an admin, it throws a ForbiddenError.
 *
 * **Prerequisites**: Both `checkAuth` and `requireAuthenticatedUser` middleware
 * must run before this middleware to ensure `currentUser` is set.
 *
 * @throws {ForbiddenError} 403 if the user's role is not 'admin'
 *
 * @example
 * ```typescript
 * app.get('/admin', requireAuthenticatedUser, onlySystemAdmin, (c) => {
 *   // Only admins can access this route
 * });
 * ```
 */
export const onlySystemAdmin = createMiddleware<ContextVars>(async (c, next) => {
  if (c.var.currentUser.role !== 'admin') throw new ForbiddenError();
  return next();
});

/**
 * Middleware that authenticates requests from Google Cloud Tasks or Cloud
 * Scheduler.
 *
 * This middleware validates that a request has a valid OIDC token (verified via
 * Google's OAuth2Client). The token must be issued for the expected service
 * account and have the correct audience (the request URL).
 *
 * Supports two types of requests:
 * 1. Cloud Tasks requests: Identified by `x-cloudtasks-queuename` and
 *    `x-cloudtasks-taskname` headers, with OIDC token
 * 2. Cloud Scheduler requests: Identified by OIDC token only (no Cloud Tasks
 *    headers)
 *
 * For all requests, the middleware:
 * 1. Extracts the OIDC token from the `Authorization: Bearer <token>` header
 * 2. Verifies the token signature using Google's public keys
 * 3. Validates the token claims (issuer, audience, expiration)
 * 4. Ensures the token's email/subject matches the expected service account
 *
 * If the request does not have a valid OIDC token from the expected service
 * account, it throws an UnauthorizedError.
 *
 * @throws {UnauthorizedError} 401 if the request lacks a valid OIDC token
 *
 * @example
 * ```typescript
 * app.post('/tasks/execute', ensureTaskAuth, (c) => {
 *   // Request is authenticated as a valid task request
 * });
 * ```
 */
export const ensureTaskAuth = createMiddleware<ContextVars>(async (c, next) => {
  const cloudTasksQueueName = c.req.header('x-cloudtasks-queuename');
  const cloudTasksTaskName = c.req.header('x-cloudtasks-taskname');
  const authHeader = c.req.header('authorization');

  const isCloudTasksRequest = cloudTasksQueueName && cloudTasksTaskName;

  // Require OIDC token for all requests
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    logger.warn(
      { headers: Object.fromEntries(c.req.raw.headers.entries()) },
      'Unauthorized request - missing Authorization Bearer token',
    );
    throw new UnauthorizedError();
  }

  const token = authHeader.substring(7); // Remove 'Bearer ' prefix

  try {
    // Get configuration to verify the expected service account
    const config = await getConfig();
    const expectedServiceAccount = config.identities.app;

    // Construct the expected audience (full URL of the request)
    // Cloud Tasks sets the audience to the exact URL it's calling
    // In Hono, c.req.url is the full URL, but we'll construct it from baseUrl
    // to ensure it matches what we specified when creating the task
    const baseUrl = await getBaseUrl();
    // Get the pathname from the request URL (handles both full URLs and paths)
    const requestPath = new URL(c.req.url).pathname;
    const requestUrl = new URL(requestPath, baseUrl).toString();

    // Verify the OIDC token using Google's OAuth2Client
    const client = new OAuth2Client();
    const ticket = await client.verifyIdToken({
      idToken: token,
      audience: requestUrl,
    });

    const payload = ticket.getPayload();
    if (!payload) {
      logger.warn('OIDC token verification returned no payload');
      throw new UnauthorizedError();
    }

    // Verify the token was issued for the expected service account
    // The 'email' claim contains the service account email
    const tokenEmail = payload.email || payload.sub;
    if (tokenEmail !== expectedServiceAccount) {
      logger.warn(
        {
          expectedServiceAccount,
          tokenEmail,
          tokenIssuer: payload.iss,
          tokenAudience: payload.aud,
        },
        'OIDC token email does not match expected service account',
      );
      throw new UnauthorizedError();
    }

    // Verify the issuer is Google
    if (payload.iss !== 'https://accounts.google.com') {
      logger.warn({ issuer: payload.iss }, 'OIDC token issuer is not Google');
      throw new UnauthorizedError();
    }

    logger.info(
      {
        queueName: cloudTasksQueueName,
        taskName: cloudTasksTaskName,
        serviceAccount: tokenEmail,
        requestType: isCloudTasksRequest ? 'Cloud Tasks' : 'Cloud Scheduler',
      },
      'Authenticated task request with OIDC token',
    );

    return next();
  } catch (error) {
    // If it's already an UnauthorizedError, re-throw it
    if (error instanceof UnauthorizedError) {
      throw error;
    }

    // Log other errors (e.g., token verification failures)
    logger.warn(
      {
        error,
        queueName: cloudTasksQueueName,
        taskName: cloudTasksTaskName,
        requestType: isCloudTasksRequest ? 'Cloud Tasks' : 'Cloud Scheduler',
      },
      'Failed to verify OIDC token for task request',
    );
    throw new UnauthorizedError();
  }
});

