import {
  getLogger,
  StatusCodes,
  isFirebaseError,
  InsufficientQuotaError,
  getReasonPhrase,
} from '@/lib';
import { type Context } from 'hono';
import { HTTPException } from 'hono/http-exception';
import { ZodError } from 'zod';
import type { StatusCode } from '@/lib';
import { handleQuotaError } from '@/lib/quota/quota-retry';

// Global error handler
const logger = getLogger('example-app');

/**
 * Map Firebase error codes to HTTP status codes
 */
const FIREBASE_STATUS_CODES: Record<string, StatusCode> = {
  'not-found': StatusCodes.NOT_FOUND,
  'already-exists': StatusCodes.CONFLICT,
  'permission-denied': StatusCodes.FORBIDDEN,
  'failed-precondition': StatusCodes.NOT_FOUND,
  'invalid-argument': StatusCodes.BAD_REQUEST,
  unauthenticated: StatusCodes.UNAUTHORIZED,
  'resource-exhausted': StatusCodes.TOO_MANY_REQUESTS,
  'deadline-exceeded': StatusCodes.GATEWAY_TIMEOUT,
  aborted: StatusCodes.CONFLICT,
  'out-of-range': StatusCodes.BAD_REQUEST,
  unimplemented: StatusCodes.NOT_IMPLEMENTED,
  internal: StatusCodes.INTERNAL_SERVER_ERROR,
  unavailable: StatusCodes.SERVICE_UNAVAILABLE,
  'data-loss': StatusCodes.INTERNAL_SERVER_ERROR,
};

/**
 * Hono error handler middleware.
 *
 * When used with the `.onError` method, it will catch all errors thrown by the
 * application and return a JSON response with the error message.
 *
 * @example
 * ```typescript
 * app.onError(onError);
 * ```
 *
 * @param err the error to handle
 * @param c the Hono context of the request
 * @returns a JSON response with the error message
 */
export default async function onError(err: Error, c: Context): Promise<Response> {
  // Handle InsufficientQuotaError for task routes by rescheduling
  if (err instanceof InsufficientQuotaError) {
    const response = await handleQuotaError(err, c);
    if (response) {
      return response;
    }
    // If not a task route, fall through to normal error handling
  }

  if (err instanceof HTTPException) {
    const response = err.getResponse();
    const contentType = response.headers.get('content-type') ?? '';
    if (contentType.includes('application/json')) {
      return response;
    }

    const message = err.message || getReasonPhrase(response.status);
    const headers = new Headers(response.headers);
    headers.set('content-type', 'application/json; charset=UTF-8');

    return new Response(JSON.stringify({ error: message, message }), {
      status: response.status,
      headers,
    });
  }
  if (err instanceof ZodError) {
    const errors = err.issues.map((issue) => ({
      path: issue.path.join('.'),
      message: issue.message,
      code: issue.code,
    }));
    return c.json(
      {
        error: 'Unprocessable Entity',
        details: errors,
        message: err.message,
        stack: err.stack,
        type: err.type,
      },
      StatusCodes.UNPROCESSABLE_ENTITY,
    );
  }
  // Check if error is a FirebaseError
  if (isFirebaseError(err)) {
    const { code, message } = err;
    const statusCode = FIREBASE_STATUS_CODES[code] ?? StatusCodes.INTERNAL_SERVER_ERROR;
    return c.json({ error: code, message }, statusCode);
  }

  // Normalize common “not found” messages produced by lower layers (e.g. zfa)
  const message = err.message ?? '';
  if (
    message.includes('returned no documents') ||
    message.includes('not found') ||
    message.includes('does not exist')
  ) {
    return c.json({ error: 'not-found', message }, StatusCodes.NOT_FOUND);
  }

  logger.error({ err, path: new URL(c.req.url).pathname }, 'Internal server error');
  return c.json({ error: 'Internal Server Error' }, StatusCodes.INTERNAL_SERVER_ERROR);
}

