import { describe, it, expect, vi, beforeEach } from 'vitest';
import { router } from '@/testing/router';
import {
  mockBigQueryInsertChannelSnapshots,
  mockYouTubeChannelData,
  mockYouTubeChannelData2,
  mockYouTubeInstance,
} from '@/testing';
import { InsufficientQuotaError, YouTubeClient } from '@/lib';

describe('channel statistics task', () => {
  beforeEach(async () => {
    vi.clearAllMocks();
  });

  it('inserts channel snapshots into BigQuery', async () => {
    const channelIds = [mockYouTubeChannelData.id, mockYouTubeChannelData2.id];

    const res = await router.asTask().post('/tasks/channelStatsUpdate', {
      body: {
        channelIds,
      },
    });

    const body = await res.json();
    expect(body).toEqual({ accepted: true });
    expect(res.status).toBe(200);

    expect(mockBigQueryInsertChannelSnapshots).toHaveBeenCalledTimes(1);
    const insertedChannelSnapshots = mockBigQueryInsertChannelSnapshots.mock.calls[0]?.[0];
    expect(insertedChannelSnapshots).toBeDefined();
    expect(insertedChannelSnapshots).toHaveLength(2);
    expect(insertedChannelSnapshots![0]).toMatchObject({
      channelId: mockYouTubeChannelData.id,
      channelTitle: mockYouTubeChannelData.snippet.title,
      publishedAt: new Date(mockYouTubeChannelData.snippet.publishedAt),
      views: parseInt(mockYouTubeChannelData.statistics.viewCount),
      subscribers: parseInt(mockYouTubeChannelData.statistics.subscriberCount),
      videos: parseInt(mockYouTubeChannelData.statistics.videoCount),
      hiddenSubscriberCount: mockYouTubeChannelData.statistics.hiddenSubscriberCount,
    });
  });

  it('returns an error if no channel data is returned from the YouTube API', async () => {
    const channelIds = ['invalid-channel-id'];

    mockYouTubeInstance.channels.list.mockResolvedValueOnce({
      data: { items: [] },
    });

    const res = await router.asTask().post('/tasks/channelStatsUpdate', {
      body: {
        channelIds,
      },
    });

    expect(res.status).toBe(400);
    const body = (await res.json()) as { error?: string; message?: string };
    expect(body).toMatchObject({
      error: 'No channel data returned',
      message: 'No channel data returned',
    });

    expect(mockBigQueryInsertChannelSnapshots).not.toHaveBeenCalled();
  });

  it('reschedules task when quota is exhausted fetching channel statistics', async () => {
    const spy = vi.spyOn(YouTubeClient, 'create').mockResolvedValueOnce({
      getChannelStatistics: vi.fn().mockRejectedValue(new InsufficientQuotaError('Quota exceeded')),
    } as unknown as YouTubeClient);

    // Mock QuotaManager.getQuotaSnapshot to return exhausted minute window
    const { QuotaManager } = await import('@/lib/quota/quota-manager');
    const mockGetQuotaSnapshot = vi.spyOn(QuotaManager.prototype, 'getQuotaSnapshot');
    mockGetQuotaSnapshot.mockResolvedValue({
      minute: {
        key: '2025-01-15-10-30',
        usage: 0,
        reservations: 0,
        limit: 250,
        available: 0,
        percentageUsed: 0,
      },
      hour: {
        key: '2025-01-15-10',
        usage: 0,
        reservations: 0,
        limit: 1000,
        available: 1000,
        percentageUsed: 0,
      },
      day: {
        key: '2025-01-15',
        usage: 0,
        reservations: 0,
        limit: 10000,
        available: 10000,
        percentageUsed: 0,
      },
    });

    const { TasksClient } = await import('@/lib');
    const mockTaskEnqueue = vi.fn().mockResolvedValue('rescheduled-task-123');
    TasksClient.default = vi.fn().mockResolvedValue({ enqueueTask: mockTaskEnqueue });

    const res = await router.asTask().post('/tasks/channelStatsUpdate', {
      body: {
        channelIds: [mockYouTubeChannelData.id],
      },
    });

    // Should return 202 Accepted with deferred flag
    expect(res.status).toBe(202);
    const body = await res.json();
    expect(body).toMatchObject({
      accepted: true,
      deferred: true,
      deferralReason: 'quota_exhausted',
      exhaustedWindows: ['minute'],
      taskRetryCount: null,
      taskExecutionCount: null,
    });
    expect(body.retryAt).toBeDefined();
    expect(body.retryDelaySeconds).toBeGreaterThan(0);
    expect(body.taskName).toBe('rescheduled-task-123');

    // Should have enqueued a retry task
    expect(mockTaskEnqueue).toHaveBeenCalledOnce();

    spy.mockRestore();
    mockGetQuotaSnapshot.mockRestore();
  });
});

