import { describe, it, expect, beforeEach, vi } from 'vitest';
import { router } from '@/testing/router';
import { resetConfig, withConfig } from '@/lib/gcp/config';
import * as configModule from '@/lib/gcp/config';

describe('Health and Readiness Endpoints', () => {
  beforeEach(() => {
    // Reset config cache before each test
    // Note: We don't call vi.restoreAllMocks() here because it would restore
    // the global Secret Manager mock that we need for withConfig to work
    resetConfig();
  });

  describe('GET /healthz', () => {
    it('returns 200 with status ok', async () => {
      const response = await router.get('/healthz');
      expect(response.status).toBe(200);
      const body = await response.json();
      expect(body).toEqual({ status: 'ok' });
    });
  });

  describe('GET /readyz', () => {
    it('returns 200 with ready: true when config is available', async () => {
      // Use withConfig to customize config and ensure it's available
      // The global mock provides a base config, we just customize what we need
      await withConfig(
        {
          projectId: 'test-project',
          region: 'us-central1',
          stack: 'dev',
        },
        async () => {
          const response = await router.get('/readyz');
          expect(response.status).toBe(200);
          const body = await response.json();
          expect(body).toEqual({ ready: true });
        },
      );
    });

    it('returns 503 with Service Unavailable when config is not available', async () => {
      // Mock getConfig to fail (withConfig requires valid config, so we still
      // need to mock for failure case)
      vi.spyOn(configModule, 'getConfig').mockRejectedValue(
        new Error('Configuration not available'),
      );

      const response = await router.get('/readyz');
      expect(response.status).toBe(503);
      // HTTPException.getResponse() returns a Response - check if it's JSON or
      // text
      const contentType = response.headers.get('content-type');
      if (contentType?.includes('application/json')) {
        const body = await response.json();
        expect(body).toHaveProperty('message');
        expect(body.message).toContain('Configuration not available');
      } else {
        // If it's text, just verify the status code
        const text = await response.text();
        expect(text).toContain('Configuration not available');
      }
    });
  });
});

