.get('/readyz', async (c) => {
  try {
    // Check if configuration can be loaded (minimal readiness check)
    await getConfig();
    // TODO: Other readiness checks to consider:
    // - Firestore database connections
    // - BigQuery dataset connections
    // - Cloud Tasks queue connections
    // - YouTube API connections
    // - Mailgun API connections
    // - OAuth providers
    return c.json({ ready: true }, 200);
  } catch (error) {
    // For readiness checks, dependency failures indicate service
    // unavailability. Throw ServiceUnavailableError so the error middleware
    // returns 503. Other errors (like programming bugs) will bubble up as 500
    throw new ServiceUnavailableError('Configuration not available', { cause: error });
  }
});

