 12→describe('analysis lifecycle taxonomy', () => {
 13→  it('defines stable reason-code and stage enums for N/A classification', () => {
 14→    expect(ANALYSIS_NA_TRACE_STAGES).toEqual(['ingest', 'normalize', 'aggregate', 'report']);
 15→    expect(ANALYSIS_NA_REASON_CODES).toContain('ingest.waiting_for_first_fetch');
 16→    expect(ANALYSIS_NA_REASON_CODES).toContain('aggregate.score_non_finite');
