 18→  });
 19→});
 20→
 21→describe('analysis lifecycle metric mapping', () => {
 22→  it('returns loading state while statistics are loading', () => {
 23→    const state = resolveAnalysisMetricState({
 24→      analysisStatus: 'running',
 25→      loading: true,
 26→      hasStatisticsRow: false,
 27→      metricValue: undefined,
 28→    });
 29→    expect(state).toBe('loading');
 30→  });
 31→
 32→  it('classifies pending/no-row as ingest-waiting with no-data-yet report label', () => {
 33→    const display = resolveAnalysisMetricDisplay({
 34→      analysisStatus: 'pending',
 35→      loading: false,
 36→      hasStatisticsRow: false,
 37→      metricValue: undefined,
 38→      formatter: (value) => value.toString(),
 39→    });
 40→
 41→    const expectedTrace = [
