} from './analysis-lifecycle';

describe('analysis lifecycle taxonomy', () => {
  it('defines stable reason-code and stage enums for N/A classification', () => {
    expect(ANALYSIS_NA_TRACE_STAGES).toEqual(['ingest', 'normalize', 'aggregate', 'report']);
    expect(ANALYSIS_NA_REASON_CODES).toContain('ingest.waiting_for_first_fetch');
