    expect(display.label).toBe('Failed');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('maps running with partial statistics row to In Progress (formatAnalysisMetric)', () => {
    const display = formatAnalysisMetric({
      analysisStatus: 'running',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
    });
    expect(display).toBe('In Progress');
  });

  it('maps failed with partial statistics row to Failed', () => {
    const display = formatAnalysisMetric({
      analysisStatus: 'failed',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
