import { describe, expect, it } from 'vitest';
import {
  ANALYSIS_NA_REASON_CODES,
  ANALYSIS_NA_TRACE_STAGES,
  formatAnalysisMetric,
  resolveAnalysisMetricDisplay,
  resolveAnalysisMetricState,
  resolveOpportunityScoreDisplay,
  serializeNaReasonTrace,
} from './analysis-lifecycle';

describe('analysis lifecycle taxonomy', () => {
  it('defines stable reason-code and stage enums for N/A classification', () => {
    expect(ANALYSIS_NA_TRACE_STAGES).toEqual(['ingest', 'normalize', 'aggregate', 'report']);
    expect(ANALYSIS_NA_REASON_CODES).toContain('ingest.waiting_for_first_fetch');
    expect(ANALYSIS_NA_REASON_CODES).toContain('aggregate.score_non_finite');
    expect(ANALYSIS_NA_REASON_CODES).toContain('report.not_available');
  });
});

describe('analysis lifecycle metric mapping', () => {
  it('returns loading state while statistics are loading', () => {
    const state = resolveAnalysisMetricState({
      analysisStatus: 'running',
      loading: true,
      hasStatisticsRow: false,
      metricValue: undefined,
    });
    expect(state).toBe('loading');
  });

  it('classifies pending/no-row as ingest-waiting with no-data-yet report label', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'pending',
      loading: false,
      hasStatisticsRow: false,
      metricValue: undefined,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.waiting_for_first_fetch',
      'normalize.snapshot_pending',
      'aggregate.metric_row_missing',
      'report.no_data_yet',
    ].join(' > ');
    expect(display.label).toBe('No Data Yet');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('classifies running/no-row as ingest in-progress', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'running',
      loading: false,
      hasStatisticsRow: false,
      metricValue: undefined,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.fetch_in_progress',
      'normalize.snapshot_pending',
      'aggregate.metric_row_missing',
      'report.in_progress',
    ].join(' > ');
    expect(display.label).toBe('In Progress');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('classifies failed/no-row as ingest failed', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'failed',
      loading: false,
      hasStatisticsRow: false,
      metricValue: undefined,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.fetch_failed',
      'normalize.snapshot_missing',
      'aggregate.metric_row_missing',
      'report.failed',
    ].join(' > ');
    expect(display.label).toBe('Failed');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('classifies cancelled/no-row as cancelled ingest trace instead of fetch failed', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'cancelled',
      loading: false,
      hasStatisticsRow: false,
      metricValue: undefined,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.fetch_cancelled',
      'normalize.snapshot_missing',
      'aggregate.metric_row_missing',
      'report.failed',
    ].join(' > ');
    expect(display.label).toBe('Failed');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('classifies succeeded/no-row as no indexed results', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'succeeded',
      loading: false,
      hasStatisticsRow: false,
      metricValue: undefined,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.no_results_indexed',
      'normalize.snapshot_missing',
      'aggregate.metric_row_missing',
      'report.not_available',
    ].join(' > ');
    expect(display.label).toBe('Not Available');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('renders zero-value metrics as complete numeric output', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'succeeded',
      loading: false,
      hasStatisticsRow: true,
      metricValue: 0,
      formatter: (value) => value.toString(),
    });

    expect(display.label).toBe('0');
    expect(display.naReasonTrace).toEqual([]);
  });

  it('maps running with partial statistics row to In Progress', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'running',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.results_indexed',
      'normalize.metric_missing',
      'aggregate.metric_value_missing',
      'report.in_progress',
    ].join(' > ');
    expect(display.state).toBe('in_progress');
    expect(display.label).toBe('In Progress');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('maps failed with partial statistics row to Failed', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'failed',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.results_indexed',
      'normalize.metric_missing',
      'aggregate.metric_value_missing',
      'report.failed',
    ].join(' > ');
    expect(display.state).toBe('failed');
    expect(display.label).toBe('Failed');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('maps running with partial statistics row to In Progress (formatAnalysisMetric)', () => {
    const display = formatAnalysisMetric({
      analysisStatus: 'running',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
    });
    expect(display).toBe('In Progress');
  });

  it('maps failed with partial statistics row to Failed (formatAnalysisMetric)', () => {
    const display = formatAnalysisMetric({
      analysisStatus: 'failed',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
    });
    expect(display).toBe('Failed');
  });

  it('maps null metrics in an existing row to Not Available', () => {
    const display = resolveAnalysisMetricDisplay({
      analysisStatus: 'succeeded',
      loading: false,
      hasStatisticsRow: true,
      metricValue: null,
      formatter: (value) => value.toString(),
    });

    const expectedTrace = [
      'ingest.results_indexed',
      'normalize.metric_missing',
      'aggregate.metric_value_missing',
      'report.not_available',
    ].join(' > ');
    expect(display.label).toBe('Not Available');
    expect(serializeNaReasonTrace(display.naReasonTrace)).toBe(expectedTrace);
  });

  it('formatAnalysisMetric preserves existing formatting output contract', () => {
    const display = formatAnalysisMetric({
      analysisStatus: 'succeeded',
      loading: false,
      hasStatisticsRow: true,
      metricValue: 42,
      formatter: (value) => `${value} value`,
    });

    expect(display).toBe('42 value');
  });
});

